Write-Host "========================================" -ForegroundColor Cyan
Write-Host "Building $Class rotation..." -ForegroundColor Cyan
Write-Host "========================================" -ForegroundColor Cyan

# Verify directories exist
if (-not (Test-Path $componentsDir)) {
